diagnostics_hook:
#!/bin/bash
INPUT=$(head -c 65536); FILE=$(printf '%s' "$INPUT" | jq -r '.tool_input.file_path // ""')
[[ "$FILE" != *.rb ]] && { echo '{"decision":"approve"}'; exit 0; }
ERRORS=$(bundle exec rubocop --format simple "$FILE" 2>&1 | head -20)
[ -n "$ERRORS" ] && echo "$ERRORS" >&2
echo '{"decision":"approve"}'
